item.content:encoded:
/* Ocultar solo el menú de navegación en página Welcome */
.page-id-301 .primary-navigation,
.page-id-301 #site-navigation,
.page-id-301 .main-navigation,
.page-id-301 nav.header-navigation {
    display: none !important;
}

/* Heredar tipografía de Kadence en popups */
.pum-container {
    font-family: var(--global-body-font-family, inherit);
    font-size: var(--global-body-font-size, 16px);
    line-height: var(--global-body-line-height, 1.6);
    color: var(--global-palette9, #333);
}

/* Títulos dentro del popup */
.pum-container h1,
.pum-container h2,
.pum-container h3 {
    font-family: var(--global-heading-font-family, inherit);
    color: var(--global-palette9, #333);
}

/* Inputs del formulario WP-Members */
.pum-container input[type="text"],
.pum-container input[type="password"],
.pum-container input[type="email"] {
    font-family: inherit;
    border: 1px solid var(--global-palette7, #ddd);
    border-radius: 4px;
    padding: 10px;
    width: 100%;
    box-sizing: border-box;
}

/* Botones del formulario */
.pum-container input[type="submit"],
.pum-container button {
    background: var(--global-palette1, #3182ce);
    color: #fff;
    border: none;
    padding: 12px 24px;
    border-radius: 4px;
    cursor: pointer;
    font-family: inherit;
    font-weight: 600;
}

.pum-container input[type="submit"]:hover,
.pum-container button:hover {
    background: var(--global-palette2, #2c5282);
}

/* Enlaces dentro del popup */
.pum-container a {
    color: var(--global-palette1, #3182ce);
    text-decoration: none;
}

.pum-container a:hover {
    color: var(--global-palette2, #2c5282);
    text-decoration: underline;
}
